INSERT INTO skill_fields (skill_id, field_id, display_override, tier, required, importance, description, options, example, extraction_hint, disambiguation_rules, sort_order) VALUES ('rfi', (SELECT id FROM field_catalog WHERE canonical_name = 'spec_section'), 'Spec Section References', 1, false, 'S', '', '"Spec sections parsed from body text"'::jsonb, '', 'Regex for MasterFormat patterns (## ## ##) + LLM extraction of written references (''Section 07 62 00'')', '', 7) ON CONFLICT (skill_id, field_id) DO NOTHING;
INSERT INTO skill_fields (skill_id, field_id, display_override, tier, required, importance, description, options, example, extraction_hint, disambiguation_rules, sort_order) VALUES ('rfi', (SELECT id FROM field_catalog WHERE canonical_name = 'csi_division'), 'CSI Division (Primary)', 1, false, 'P', '', '"Divisions 01–49 (MasterFormat)"'::jsonb, '', 'LLM reads RFI body + MasterFormat division list as context. ''Waterproofing membrane at parapet'' → Div 07. Few-shot with 30 examples.', '', 8) ON CONFLICT (skill_id, field_id) DO NOTHING;
INSERT INTO skill_fields (skill_id, field_id, display_override, tier, required, importance, description, options, example, extraction_hint, disambiguation_rules, sort_order) VALUES ('rfi', (SELECT id FROM field_catalog WHERE canonical_name = 'csi_division_secondary'), 'CSI Division (Secondary)', 1, false, 'E', '', '"Divisions 01–49 or ''None''"'::jsonb, '', 'LLM identifies secondary trade mentions. ''Steel sub to modify clip'' → Div 05. Harder when secondary is implicit.', '', 9) ON CONFLICT (skill_id, field_id) DO NOTHING;
INSERT INTO skill_fields (skill_id, field_id, display_override, tier, required, importance, description, options, example, extraction_hint, disambiguation_rules, sort_order) VALUES ('rfi', (SELECT id FROM field_catalog WHERE canonical_name = 'csi_subdivision'), 'CSI Subdivision (6-digit)', 1, false, 'S', '', '"6-digit MasterFormat sections"'::jsonb, '', 'Cascaded: if Div 07, map text to 6-digit using MasterFormat section table. ''Sheet metal flashing'' → 07 62 00.', '', 10) ON CONFLICT (skill_id, field_id) DO NOTHING;
INSERT INTO skill_fields (skill_id, field_id, display_override, tier, required, importance, description, options, example, extraction_hint, disambiguation_rules, sort_order) VALUES ('rfi', (SELECT id FROM field_catalog WHERE canonical_name = 'building_system'), 'Building System', 1, false, 'S', '', '"Envelope | Structure | MEP Rough-In | MEP Finish | Interiors/Finishes | Site/Civil | Vertical Transport | Fire/Life Safety | Specialties | General Conditions"'::jsonb, '', '10-category classification. LLM maps RFI scope to system. Simple — ''parapet flashing'' → Envelope, ''ductwork'' → MEP Rough-In.', '', 11) ON CONFLICT (skill_id, field_id) DO NOTHING;
INSERT INTO skill_fields (skill_id, field_id, display_override, tier, required, importance, description, options, example, extraction_hint, disambiguation_rules, sort_order) VALUES ('rfi', (SELECT id FROM field_catalog WHERE canonical_name = 'trade'), 'Trade(s) Responsible', 1, false, 'S', '', '"Client''s subcontractor directory"'::jsonb, '', 'NLP extraction of company names from RFI text + fuzzy match against client sub directory (Procore API). Handles abbreviations.', '', 12) ON CONFLICT (skill_id, field_id) DO NOTHING;
INSERT INTO skill_fields (skill_id, field_id, display_override, tier, required, importance, description, options, example, extraction_hint, disambiguation_rules, sort_order) VALUES ('rfi', (SELECT id FROM field_catalog WHERE canonical_name = 'project_phase'), 'Project Phase When Discovered', 1, false, 'S', '', '"Preconstruction/Buyout | Early (0–30%) | Mid (30–70%) | Late (70–95%) | Closeout/Punch"'::jsonb, '', 'Heuristic: RFI date vs. project start/end dates from Procore. Calc approx % complete. Cross-ref with schedule milestones if available.', '', 13) ON CONFLICT (skill_id, field_id) DO NOTHING;
INSERT INTO skill_fields (skill_id, field_id, display_override, tier, required, importance, description, options, example, extraction_hint, disambiguation_rules, sort_order) VALUES ('rfi', (SELECT id FROM field_catalog WHERE canonical_name = 'root_cause'), 'Root Cause (Level 1)', 2, false, 'P', '', '"Design Conflict | Missing Information | Field Condition | Code/Regulatory | Constructability | Coordination | Owner Change | Spec Clarification | Other"'::jsonb, '', 'Few-shot prompt with all 9 category definitions + disambiguation rules + 30 labeled examples. Chain-of-thought reasoning stored with label. Key: Design Conflict vs. Missing Info distinction.', '', 14) ON CONFLICT (skill_id, field_id) DO NOTHING;
INSERT INTO skill_fields (skill_id, field_id, display_override, tier, required, importance, description, options, example, extraction_hint, disambiguation_rules, sort_order) VALUES ('rfi', (SELECT id FROM field_catalog WHERE canonical_name = 'root_cause_detail'), 'Root Cause (Level 2)', 2, false, 'P', '', '"Design Conflict: Arch vs. Structural | Arch vs. MEP | MEP vs. MEP | etc. Missing Info: Detail Not Provided | Section Not Addressed | etc. Field Condition: Subsurface | Existing Conditions | etc. Coordination: Spatial | Sequencing | Access"'::jsonb, '', 'Cascaded prompt: given L1 = Design Conflict, classify L2 from filtered subcategories. Accuracy depends on L1 being correct. Chain carefully.', '', 15) ON CONFLICT (skill_id, field_id) DO NOTHING;
INSERT INTO skill_fields (skill_id, field_id, display_override, tier, required, importance, description, options, example, extraction_hint, disambiguation_rules, sort_order) VALUES ('rfi', (SELECT id FROM field_catalog WHERE canonical_name = 'urgency'), 'Urgency', 2, false, 'S', '', '"Critical (work stopped) | High (blocked within 5 days) | Standard (no immediate impact) | Low (informational/future phase)"'::jsonb, '', 'Strong text signals: ''crew waiting'', ''critical path'', ''scheduled next week'', ''mobilized'', ''work stopped''. Pattern matching + LLM classification.', '', 16) ON CONFLICT (skill_id, field_id) DO NOTHING;
INSERT INTO skill_fields (skill_id, field_id, display_override, tier, required, importance, description, options, example, extraction_hint, disambiguation_rules, sort_order) VALUES ('rfi', (SELECT id FROM field_catalog WHERE canonical_name = 'cost_impact'), 'Cost Impact (Estimated Range)', 2, false, 'S', '', '"None | Minor (<$5K) | Moderate ($5–25K) | Major ($25–100K) | Critical (>$100K)"'::jsonb, '', 'LLM identifies scope-change signals and estimates magnitude from text. ''Revised detail + new clips + manufacturer coordination'' → Moderate. Classification into ranges, not dollar estimates.', '', 17) ON CONFLICT (skill_id, field_id) DO NOTHING;
INSERT INTO skill_fields (skill_id, field_id, display_override, tier, required, importance, description, options, example, extraction_hint, disambiguation_rules, sort_order) VALUES ('rfi', (SELECT id FROM field_catalog WHERE canonical_name = 'schedule_impact'), 'Schedule Impact (Estimated Range)', 2, false, 'P', '', '"None | Minor (1–3 days) | Moderate (3–10 days) | Major (10–30 days) | Critical (>30 days / LD exposure)"'::jsonb, '', 'Text signals: ''critical path'', ''delay'', ''5 days''. LLM estimates range. Less reliable — schedule context is external to the document.', '', 18) ON CONFLICT (skill_id, field_id) DO NOTHING;
INSERT INTO skill_fields (skill_id, field_id, display_override, tier, required, importance, description, options, example, extraction_hint, disambiguation_rules, sort_order) VALUES ('rfi', (SELECT id FROM field_catalog WHERE canonical_name = 'resolution_outcome'), 'Resolution Outcome', 2, false, 'S', '', '"No Change Required | ASI / Design Revision | Change Order Generated | Claim / Dispute | Deferred / Still Open"'::jsonb, '', 'LLM reads response text + checks for ASI/CO references. ''Revised detail attached (ASI-034)'' → ASI. If no response → ''Still Open''. Clear text signals.', '', 19) ON CONFLICT (skill_id, field_id) DO NOTHING;
INSERT INTO skill_fields (skill_id, field_id, display_override, tier, required, importance, description, options, example, extraction_hint, disambiguation_rules, sort_order) VALUES ('rfi', (SELECT id FROM field_catalog WHERE canonical_name = 'preventability'), 'Preventability', 3, false, 'S', '', '"Yes-Likely (catchable in precon) | Yes-Possibly (enhanced review) | No (unforeseeable/owner-driven)"'::jsonb, '', 'LLM generates suggestion with reasoning based on root cause + description. Suggestion shown to human but NOT pre-selected. Human makes final call.', '', 20) ON CONFLICT (skill_id, field_id) DO NOTHING;
INSERT INTO skill_fields (skill_id, field_id, display_override, tier, required, importance, description, options, example, extraction_hint, disambiguation_rules, sort_order) VALUES ('rfi', (SELECT id FROM field_catalog WHERE canonical_name = 'responsibility_attribution'), 'Responsibility Attribution', 3, false, 'P', '', '"Design Team | Owner | GC Internal | Subcontractor | Regulatory/Code | Shared/Unclear"'::jsonb, '', 'LLM suggests based on root cause + text analysis. ''Per ASI from architect'' → Design Team. But politically sensitive — context matters beyond text.', '', 21) ON CONFLICT (skill_id, field_id) DO NOTHING;
INSERT INTO skill_fields (skill_id, field_id, display_override, tier, required, importance, description, options, example, extraction_hint, disambiguation_rules, sort_order) VALUES ('rfi', (SELECT id FROM field_catalog WHERE canonical_name = 'recurring_pattern'), 'Recurring Pattern', 3, false, 'P', '', '"First Instance | Recurring-Same Project | Recurring-Cross Project | Known Industry Issue"'::jsonb, '', 'After 2000+ labeled RFIs: system runs semantic similarity search against labeled corpus and flags potential matches. Before that: human knowledge only.', '', 22) ON CONFLICT (skill_id, field_id) DO NOTHING;
INSERT INTO skill_fields (skill_id, field_id, display_override, tier, required, importance, description, options, example, extraction_hint, disambiguation_rules, sort_order) VALUES ('rfi', (SELECT id FROM field_catalog WHERE canonical_name = 'related_documents'), 'Related Documents', 3, false, 'S', '', '"RFI numbers, CO numbers, ASI numbers from same project or cross-project"'::jsonb, '', 'Regex + LLM extraction of explicit doc references (RFI-###, ASI-###, CO-###). High accuracy on explicit refs. Implicit relationships (same issue, different doc) via semantic search.', '', 23) ON CONFLICT (skill_id, field_id) DO NOTHING;
