INSERT INTO skill_fields (skill_id, field_id, display_override, tier, required, importance, description, options, example, extraction_hint, disambiguation_rules, sort_order) VALUES ('contract', (SELECT id FROM field_catalog WHERE canonical_name = 'negotiability'), 'Negotiability Assessment', 3, false, 'S', '', '"Always Negotiable | Usually Negotiable | Sometimes | Rarely | Non-Negotiable (statutory/bonding)"'::jsonb, '', 'After corpus builds: system suggests based on historical outcomes with same owner. ''Owner X has negotiated this clause on 3 of 4 prior contracts.'' Before data: human only.', '', 11) ON CONFLICT (skill_id, field_id) DO NOTHING;
