INSERT INTO skill_fields (skill_id, field_id, display_override, tier, required, importance, description, options, example, extraction_hint, disambiguation_rules, sort_order) VALUES ('contract', (SELECT id FROM field_catalog WHERE canonical_name = 'recommended_action'), 'Recommended Action', 3, false, 'S', '', '"Accept As-Is | Negotiate (with suggested language) | Add Contingency | Flag for Legal | Reject/Walk"'::jsonb, '', 'LLM drafts suggestion based on risk score + deviation analysis. Shown as ''AI draft'' for human to edit — NEVER auto-populated. Highest liability risk.', '', 13) ON CONFLICT (skill_id, field_id) DO NOTHING;
