INSERT INTO skill_fields (skill_id, field_id, display_override, tier, required, importance, description, options, example, extraction_hint, disambiguation_rules, sort_order) VALUES ('change_order', (SELECT id FROM field_catalog WHERE canonical_name = 'csi_division'), 'CSI Division(s)', 1, false, 'S', '', '"Divisions 01–49 (may span multiple)"'::jsonb, '', 'Same as RFI: LLM reads CO scope description + MasterFormat. CO descriptions tend to be clearer than RFIs. Multi-division slightly harder.', '', 7) ON CONFLICT (skill_id, field_id) DO NOTHING;
