INSERT INTO skill_fields (skill_id, field_id, display_override, tier, required, importance, description, options, example, extraction_hint, disambiguation_rules, sort_order) VALUES ('submittal', (SELECT id FROM field_catalog WHERE canonical_name = 'resubmittal_reason'), 'Resubmittal Reason (if applicable)', 2, false, 'S', '', '"N/A | Sub Error | Incomplete | Reviewer Requested Alternates | Spec Disagreement | Coordination Issue | Changed Conditions"'::jsonb, '', 'If resubmittal exists, LLM reads reviewer comments to classify reason. ''Revise per spec section 03 30 00'' → Spec Disagreement.', '', 15) ON CONFLICT (skill_id, field_id) DO NOTHING;
