INSERT INTO skill_fields (skill_id, field_id, display_override, tier, required, importance, description, options, example, extraction_hint, disambiguation_rules, sort_order) VALUES ('daily_report', (SELECT id FROM field_catalog WHERE canonical_name = 'productivity_indicator'), 'Productivity Indicator', 2, false, 'P', '', '"Above Expected | On Track | Below Expected | Significantly Behind | Weather Day"'::jsonb, '', 'LLM can suggest based on crew count vs. work completed, but ''expected'' requires knowing the plan. Without schedule context, unreliable.', '', 10) ON CONFLICT (skill_id, field_id) DO NOTHING;
